import{_ as i,o as r,c as e,a2 as l}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"融资额度","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/credit-limit.md","filePath":"zh-CN/margin/credit-limit.md"}'),t={name:"margin/credit-limit.md"};function n(o,a,s,h,d,m){return r(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="融资额度" tabindex="-1">融资额度 <a class="header-anchor" href="#融资额度" aria-label="Permalink to &quot;融资额度&quot;">​</a></h1><p>融资额度是账户可借入资金的上限，根据存入的现金或转仓资产自动评估，无需手动申请初始额度。结欠金额不得超过融资额度上限。</p><p>长桥账户默认为融资账户（保证金账户），支持杠杆交易。如不需要杠杆，可降低或关闭融资额度，以避免误操作产生利息。</p><h2 id="降低融资额度" tabindex="-1">降低融资额度 <a class="header-anchor" href="#降低融资额度" aria-label="Permalink to &quot;降低融资额度&quot;">​</a></h2><ol><li>打开长桥 App，进入「资产」页面</li><li>找到「融资状态」或「我的融资额度」</li><li>点击「调整额度」，将额度调低至所需金额</li><li>确认提交，24 小时内生效</li></ol><p>每 24 小时内最多申请 2 次（新加坡账户每 24 小时限 1 次）。</p><p>降低额度不影响已有持仓，仅限制新增融资买入。如需重新开启融资，按相同流程申请提高额度即可。</p><h2 id="关闭融资额度" tabindex="-1">关闭融资额度 <a class="header-anchor" href="#关闭融资额度" aria-label="Permalink to &quot;关闭融资额度&quot;">​</a></h2><p>将融资额度调整为 0 即等同关闭融资。关闭后账户仍为保证金账户，但不可使用杠杆买入。</p><p><strong>前提条件</strong>：账户内无未平仓的融资持仓（即无结欠），且无待成交的融资买入委托。如有融资持仓，需先卖出并还清欠款后再申请关闭。</p><p><strong>确认是否有结欠</strong>：App → 资产 → 现金页，查看「融资余额」或「结欠」字段：</p><ul><li>显示 0 或为空：无结欠，可直接关闭</li><li>显示负数金额：需先还清。入金后系统将于下一结算日自动扣除，或通过换汇偿还不同币种的结欠</li></ul><h2 id="降低额度对持仓的影响" tabindex="-1">降低额度对持仓的影响 <a class="header-anchor" href="#降低额度对持仓的影响" aria-label="Permalink to &quot;降低额度对持仓的影响&quot;">​</a></h2><ul><li>降低额度不影响已有持仓，仅限制新增融资买入</li><li>持仓市值下跌导致维持保证金不足时，平台仍会发出追缴通知，与是否主动降低额度无关</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/margin/margin-requirements">保证金</a> — 初始、维持、平仓三层结构与购买力计算</li><li><a href="/wiki/margin/interest-rules">融资利息</a></li><li><a href="/wiki/margin/risk-control">账户风控</a> — 安全/中等/预警/危险四级风控状态与购买力影响</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/margin">融资融券</a></li><li><a href="/wiki/margin/interest-rules">融资利息</a></li><li><a href="/wiki/margin/margin-requirements">保证金</a></li><li><a href="/wiki/margin/risk-control">账户风控</a></li></ul>',18)])])}const p=i(t,[["render",n]]);export{u as __pageData,p as default};
